test.describe('Phase 21: Notes', () => {
  test('API routes respond (no 500)', async ({ request }) => {
    const r0 = await request.get(`${API}/vista/interop/hl7-links`);
    expect(r0.status(), '/vista/interop/hl7-links not 500').not.toBe(500);
    const r1 = await request.get(`${API}/vista/interop/hl7-messages`);
    expect(r1.status(), '/vista/interop/hl7-messages not 500').not.toBe(500);
    const r2 = await request.get(`${API}/vista/interop/hlo-status`);
    expect(r2.status(), '/vista/interop/hlo-status not 500').not.toBe(500);
    const r3 = await request.get(`${API}/vista/interop/queue-depth`);
    expect(r3.status(), '/vista/interop/queue-depth not 500').not.toBe(500);
    const r4 = await request.get(`${API}/vista/interop/summary`);
    expect(r4.status(), '/vista/interop/summary not 500').not.toBe(500);
  });

  test('UI component files exist on disk', async () => {
    const componentNames = ['page.tsx'];
    function findFile(dir: string, name: string, depth = 0): boolean {
      if (depth > 6) return false;
      try {
        for (const entry of readdirSync(dir, { withFileTypes: true })) {
          if (entry.isFile() && entry.name === name) return true;
          if (entry.isDirectory() && !entry.name.startsWith('.') && entry.name !== 'node_modules') {
            if (findFile(join(dir, entry.name), name, depth + 1)) return true;
          }
        }
      } catch {
        /* permission error or similar */
      }
      return false;
    }
    let found = 0;
    for (const name of componentNames) {
      if (findFile(join(ROOT, 'apps'), name)) found++;
    }
    expect(found, `Expected >= 1 of 1 UI files for Phase 21`).toBeGreaterThan(0);
  });

  test('integration-pending responses are compliant', async ({ request }) => {
    // Spot-check first accessible route for pending compliance
    const res = await request.get(`${API}/vista/interop/hl7-links`);
    expect(res.status(), '/vista/interop/hl7-links should respond').toBeDefined();
    if (res.status() === 200) {
      const body = await res.json().catch(() => null);
      if (body && body.status === 'integration-pending') {
        expect(body, 'integration-pending must have nextSteps').toHaveProperty('nextSteps');
      }
    }
  });
});
